<script setup lang="ts">
const supabase=useSupabaseClient<any>(),base=ref<any>(null),state=ref<any>(null),busy=ref(''),notice=ref(''),preview=ref<any>(null),cohortResult=ref<any>(null)
const disclosure=reactive({fields:['pattern_summary','aggregate_outcomes'],audience:'member_network',subject_type:'contribution',commit:false})
const compatibility=reactive({contribution_id:'',project_id:'',runtime:'web',data_store:'managed',deployment:'continuous',traffic_tier:'small',regulated:false})
const immune=reactive({contribution_id:'',failure_mode:'',trigger_class:'regression',severity:'medium',symptoms:[] as string[],versions:[] as string[]})
const escrow=reactive({contribution_id:'',adapter_recipe:'',tests:'',scope:'single organization',duration_days:365})
const settlement=reactive({adoption_id:'',baseline_value_cents:0,treatment_value_cents:0,baseline_samples:20,treatment_samples:20,confidence:.9,proof_digest:''})
const cohort=reactive({archetype:'saas',stage:'early_revenue',team_size:'2_5',objective:'ship_faster'})
const fields=['pattern_summary','problem_class','prerequisites','aggregate_outcomes','verification','source_code','repository','customer_identity','raw_dataset','private_prompts','contract_text']
async function authed<T>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:session?.access_token?{authorization:`Bearer ${session.access_token}`}:{}})}
const dollars=(c:any)=>new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(Number(c||0)/100)
const benchmark=(key:string,value:any)=>key.includes('credit_cents')?dollars(value):typeof value==='number'?`${value}%`:String(value).replaceAll('_',' ')
async function load(){try{[base.value,state.value]=await Promise.all([authed('/api/hivemind/economy'),authed('/api/hivemind/advanced')]);compatibility.contribution_id||=base.value.marketplace?.[0]?.id||'';compatibility.project_id||=base.value.projects?.[0]?.id||'';immune.contribution_id||=base.value.contributions?.[0]?.id||'';escrow.contribution_id||=base.value.contributions?.[0]?.id||'';settlement.adoption_id||=base.value.adoptions?.find((x:any)=>x.status==='canary')?.id||''}catch(e:any){notice.value=e?.data?.message||e?.message}}
async function act(action:string,values:any){busy.value=action;notice.value='';try{const result:any=await authed('/api/hivemind/advanced',{method:'POST',body:{action,...values}});if(action==='disclosure')preview.value=result;if(action==='cohort')cohortResult.value=result;notice.value=action==='settle'?`Settlement decision: ${result.settlement.decision.replaceAll('_',' ')}`:`${action.replaceAll('_',' ')} completed with a proof record.`;await load()}catch(e:any){notice.value=e?.data?.message||e?.message||'Advanced Hivemind action failed.'}finally{busy.value=''}}
function toggleField(field:string){const set=new Set(disclosure.fields);set.has(field)?set.delete(field):set.add(field);disclosure.fields=[...set]}
function centsFrom(event:Event,key:'baseline_value_cents'|'treatment_value_cents'){settlement[key]=Math.round(Number((event.target as HTMLInputElement).value||0)*100)}
onMounted(()=>{load();const timer=setInterval(load,15000);onUnmounted(()=>clearInterval(timer))})
</script>
<template><section class="advanced"><header><div><span>HIVEMIND CONTROL PLANE</span><h2>Compound intelligence.<br><em>Contain its risks.</em></h2></div><p>Advanced controls appear here without changing established destinations. Each network action carries privacy, causality, compatibility, fraud, consent, and rollback evidence.</p></header><div v-if="!state" class="loading">Loading the network control plane…</div><template v-else>
<div class="ticker" aria-label="Live portfolio opportunities"><b>LIVE OPPORTUNITY TICKER</b><div v-if="state.opportunities.length" class="ticker-track"><span v-for="x in state.opportunities" :key="x.id"><i/>{{x.title}} · {{dollars(x.predicted_value_cents)}} · {{Math.round(x.confidence*100)}}%</span></div><span v-else>No open opportunities yet.</span><button @click="act('opportunities',{})">Refresh graph</button></div>
<nav class="control-index"><a href="#disclosure">01 Privacy compiler</a><a href="#compatibility">02 Compatibility</a><a href="#settlement">03 Causal credits</a><a href="#immunity">04 Immune network</a><a href="#escrow">05 Escrow</a><a href="#cohorts">06 Synthetic cohorts</a></nav>
<div class="advanced-grid"><article id="disclosure" class="module wide"><div class="module-head"><div><span>01 · COMPOSITION-AWARE PRIVACY</span><h3>Founder disclosure dial</h3></div><div class="budget"><b>{{state.privacy.remaining}}</b><small>of {{state.privacy.budget}} privacy points remaining</small></div></div><p>Preview the exact network payload and inference cost. Unsafe fields cannot be approved—even if selected.</p><div class="field-grid"><button v-for="field in fields" :key="field" :class="{selected:disclosure.fields.includes(field),blocked:['source_code','repository','customer_identity','raw_dataset','private_prompts','contract_text'].includes(field)}" @click="toggleField(field)">{{field.replaceAll('_',' ')}}</button></div><div class="inline"><select v-model="disclosure.audience"><option value="private">Private</option><option value="member_network">Member network</option><option value="public">Public</option></select><button @click="act('disclosure',{...disclosure,commit:false})">Preview compiled disclosure</button></div><div v-if="preview" class="receipt"><div><span>Decision</span><b>{{preview.decision}}</b></div><div><span>Inference risk</span><b>{{preview.inference_risk}}/100</b></div><div><span>Budget cost</span><b>{{preview.budget_cost}}</b></div><div><span>Approved</span><b>{{preview.approved_fields.length}}</b></div><p>Rejected: {{preview.rejected_fields.join(', ')||'none'}}</p><button v-if="preview.decision==='allow'" @click="act('disclosure',{...disclosure,commit:true})">Commit privacy receipt</button></div></article>

<article id="compatibility" class="module"><span>02 · LOCAL ADAPTER COMPILER</span><h3>Compatibility without code transfer</h3><p>Translate an abstract pattern into a local implementation and test plan. The origin implementation remains invisible.</p><form @submit.prevent="act('compatibility',compatibility)"><select v-model="compatibility.contribution_id" required><option disabled value="">Verified capability</option><option v-for="x in base.marketplace" :key="x.id" :value="x.id">{{x.title}}</option></select><select v-model="compatibility.project_id"><option value="">No workspace yet</option><option v-for="p in base.projects" :key="p.id" :value="p.id">{{p.name}}</option></select><div class="two"><input v-model="compatibility.runtime" placeholder="Runtime"><input v-model="compatibility.data_store" placeholder="Data store"></div><label><input v-model="compatibility.regulated" type="checkbox"> Regulated environment</label><button>Create local adapter plan</button></form><small>{{state.plans.length}} plans · contract, privacy, performance, journey, and rollback tests required</small></article>

<article id="settlement" class="module"><span>03 · CAUSAL CREDIT CLEARING</span><h3>Pay only for incremental value</h3><p>Compare a matched pre-adoption baseline with the treatment window. Low samples, implausible lifts, and weak confidence are reviewed or blocked.</p><form @submit.prevent="act('settle',settlement)"><select v-model="settlement.adoption_id" required><option disabled value="">Canary adoption</option><option v-for="a in base.adoptions" :key="a.id" :value="a.id">{{a.contribution?.title}} · {{a.status}}</option></select><div class="two"><label>Baseline value ($)<input :value="settlement.baseline_value_cents/100" type="number" @input="centsFrom($event,'baseline_value_cents')"></label><label>Treatment value ($)<input :value="settlement.treatment_value_cents/100" type="number" @input="centsFrom($event,'treatment_value_cents')"></label><label>Baseline samples<input v-model.number="settlement.baseline_samples" type="number" min="1"></label><label>Treatment samples<input v-model.number="settlement.treatment_samples" type="number" min="1"></label></div><label>Confidence {{Math.round(settlement.confidence*100)}}%<input v-model.number="settlement.confidence" type="range" min=".5" max="1" step=".01"></label><input v-model="settlement.proof_digest" required placeholder="Independent verification digest"><button>Run causal and fraud settlement</button></form><small>{{state.settlements.length}} causal settlements · {{state.fraud.filter((x:any)=>x.verdict==='blocked').length}} blocked claims</small></article>

<article id="immunity" class="module"><span>04 · NETWORK IMMUNE SYSTEM</span><h3>One failure protects every adopter</h3><p>Publish only a sanitized failure signature. Active signals pause new adoptions and canary expansion before a regression propagates.</p><form @submit.prevent="act('immune_signal',immune)"><select v-model="immune.contribution_id"><option value="">Portfolio-wide signal</option><option v-for="x in base.contributions" :key="x.id" :value="x.id">{{x.title}}</option></select><textarea v-model="immune.failure_mode" required rows="3" placeholder="Sanitized failure mode—no source, customers, or raw evidence"></textarea><div class="two"><select v-model="immune.severity"><option>low</option><option>medium</option><option>high</option><option>critical</option></select><input v-model="immune.trigger_class" placeholder="Trigger class"></div><button>Publish immune signal</button></form><div class="signal-list"><div v-for="x in state.immune_signals.slice(0,4)" :key="x.id"><i :class="x.severity"/><b>{{x.signal_class}}</b><small>{{x.severity}} · raw evidence never shared</small></div></div></article>

<article id="escrow" class="module"><span>05 · ENCRYPTED CAPABILITY ESCROW</span><h3>License derivatives, never the original</h3><p>Seal an adapter recipe and tests with the connector vault key. Network members can receive only consented, licensed derivative adapters.</p><form @submit.prevent="act('escrow',escrow)"><select v-model="escrow.contribution_id" required><option disabled value="">Your contribution</option><option v-for="x in base.contributions" :key="x.id" :value="x.id">{{x.title}}</option></select><textarea v-model="escrow.adapter_recipe" required rows="3" type="password" placeholder="Private adapter recipe (encrypted at rest)"></textarea><textarea v-model="escrow.tests" rows="2" placeholder="Private verification contract"></textarea><div class="two"><input v-model="escrow.scope" placeholder="License scope"><input v-model.number="escrow.duration_days" type="number" min="1" max="3650"></div><button>Seal encrypted escrow</button></form><small>{{state.escrows.length}} sealed records · no raw release · no resale · no training use</small></article>

<article id="cohorts" class="module wide"><div class="module-head"><div><span>06 · ZERO-DATA COLD START</span><h3>Synthetic founder benchmarks</h3></div><b class="synthetic">SYNTHETIC · NOT OBSERVED</b></div><p>Get useful directional benchmarks before the network has a privacy-safe real cohort. Synthetic results are never presented as member evidence.</p><form class="cohort-form" @submit.prevent="act('cohort',cohort)"><select v-model="cohort.archetype"><option>saas</option><option>marketplace</option><option>services</option><option>fintech</option><option>legaltech</option><option>infrastructure</option></select><select v-model="cohort.stage"><option>idea</option><option>prototype</option><option>early_revenue</option><option>growth</option></select><select v-model="cohort.team_size"><option>solo</option><option>2_5</option><option>6_20</option><option>21_plus</option></select><select v-model="cohort.objective"><option>ship_faster</option><option>reduce_cost</option><option>grow_revenue</option><option>reduce_risk</option></select><button>Generate cohort</button></form><div v-if="cohortResult" class="benchmarks"><div v-for="(value,key) in cohortResult.synthetic_benchmarks" :key="key"><span>{{String(key).replaceAll('_',' ')}}</span><b>{{benchmark(String(key),value)}}</b></div></div></article></div>
<p v-if="notice" class="notice" role="status">{{notice}}</p></template></section></template>
<style scoped>
.advanced{padding:90px clamp(16px,3vw,42px);background:#07100c;color:#edf8f1}.advanced>header{max-width:1180px;margin:auto;display:grid;grid-template-columns:1.4fr 1fr;gap:8vw;align-items:end}.advanced>header span,.module>span,.module-head span{font:700 9px JetBrains Mono,monospace;letter-spacing:.13em;color:#66c792}.advanced h2{margin:16px 0 0;font-size:clamp(45px,6vw,82px);line-height:.95;letter-spacing:-.06em;font-weight:480}.advanced h2 em{font-style:normal;color:#77857d}.advanced>header p,.module p{color:#8b9991;font-size:12px;line-height:1.7}.loading{padding:40px;text-align:center}.ticker,.control-index,.advanced-grid{max-width:1180px;margin:24px auto 0}.ticker{display:grid;grid-template-columns:auto 1fr auto;gap:18px;align-items:center;overflow:hidden;border:1px solid #294235;background:#0c1912;padding:13px 16px;font-size:9px}.ticker> b{color:#6ed09b}.ticker-track{display:flex;gap:45px;overflow:hidden;white-space:nowrap}.ticker-track i{display:inline-block;width:6px;height:6px;border-radius:50%;background:#58d18d;margin-right:7px}.ticker button,.module button{border:0;border-radius:8px;background:#eaf7ef;color:#07100c;padding:9px 12px;font-size:10px;font-weight:700}.control-index{display:flex;gap:8px;flex-wrap:wrap}.control-index a{border:1px solid #263a30;border-radius:99px;padding:8px 10px;color:#8fa097;text-decoration:none;font-size:8px}.advanced-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.module{scroll-margin-top:20px;border:1px solid #263a30;border-radius:16px;background:#0c1510;padding:21px}.module.wide{grid-column:1/-1}.module h3{margin:6px 0 0;font-size:22px;letter-spacing:-.035em}.module-head{display:flex;justify-content:space-between;gap:15px}.budget{text-align:right}.budget b{display:block;font-size:28px}.budget small,.module small{color:#73837a;font-size:9px}.field-grid{display:flex;gap:6px;flex-wrap:wrap;margin:16px 0}.field-grid button{border:1px solid #32463b;background:transparent;color:#7f9187}.field-grid button.selected{border-color:#66c792;background:#183425;color:#a8e7c2}.field-grid button.blocked{color:#d9978c;text-decoration:line-through}.inline,.two,.cohort-form{display:grid;grid-template-columns:1fr 1fr;gap:8px}.inline{grid-template-columns:1fr auto}.module form{display:grid;gap:9px;margin-top:16px}.module input,.module select,.module textarea{width:100%;border:1px solid #304038;border-radius:8px;background:#111d17;color:#edf8f1;padding:10px;font-size:11px}.module label{font-size:9px;color:#8a9a91}.receipt,.benchmarks{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-top:14px;border:1px solid #345443;background:#0f2017;padding:12px}.receipt span,.benchmarks span{display:block;color:#779085;font-size:8px}.receipt p,.receipt button{grid-column:1/-1}.signal-list{margin-top:12px}.signal-list div{display:grid;grid-template-columns:auto 1fr auto;gap:8px;padding:8px;border-top:1px solid #26372e;font-size:9px}.signal-list i{width:7px;height:7px;border-radius:50%;background:#e1b45c}.signal-list i.high,.signal-list i.critical{background:#ed725f}.synthetic{font:8px JetBrains Mono,monospace;color:#e0b562}.cohort-form{grid-template-columns:repeat(5,1fr)!important}.benchmarks b{font-size:17px}.notice{position:sticky;bottom:14px;max-width:720px;margin:16px auto 0;padding:12px 15px;border-radius:10px;background:#eaf7ef;color:#07100c;font-size:11px}@media(max-width:760px){.advanced>header,.advanced-grid{grid-template-columns:1fr}.module.wide{grid-column:auto}.ticker{grid-template-columns:1fr}.control-index{overflow:auto;flex-wrap:nowrap}.cohort-form,.receipt,.benchmarks{grid-template-columns:1fr 1fr!important}.module-head{display:block}.budget{text-align:left;margin-top:10px}}
</style>
